### What are Type Annotations?

Type annotations explicitly specify the type of a variable, function parameter, or return value.

### Variable Annotations

```typescript
let name: string = "Alice";
let age: number = 30;
let isActive: boolean = true;
```

### Parameter Annotations

```typescript
function greet(name: string): void {
  console.log(`Hello, ${name}`);
}
```

### Return Type Annotations

```typescript
function add(a: number, b: number): number {
  return a + b;
}
```

### Array Type Annotations

```typescript
let numbers: number[] = [1, 2, 3];
let names: Array<string> = ["Alice", "Bob"];
```

### Union Type Annotations

```typescript
let id: string | number;
id = "abc123"; // OK
id = 42; // OK
// id = true; // Error
```

### Optional Property Annotations

```typescript
function greet(name?: string): void {
  console.log(`Hello, ${name ?? "Guest"}`);
}
```

### Syntax

```
variableName: type
```

> **Key Point:** Type annotations are optional when TypeScript can infer the type from the value.

codeExample:
// Basic annotations
let message: string = "Hello";
let count: number = 42;
let completed: boolean = false;

// Function annotations
function multiply(x: number, y: number): number {
  return x * y;
}

// Annotation with union type
let status: "active" | "inactive" = "active";

// Array annotation
let items: string[] = ["a", "b", "c"];
